"use strict";(self.webpackChunkbcsd_blog=self.webpackChunkbcsd_blog||[]).push([[1333],{8343:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"/posts/introduce-Game-2025","metadata":{"permalink":"/game/posts/introduce-Game-2025","source":"@site/@game/posts/introduce-Game-2025.mdx","title":"BCSD \uac00\uc774\ub4dc: \uac8c\uc784","description":"\uac8c\uc784 \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!","date":"2025-05-05T00:00:00.000Z","tags":[{"label":"Game","permalink":"/game/tags/game"},{"label":"\ud2b8\ub799 \uc18c\uac1c","permalink":"/game/tags/\ud2b8\ub799-\uc18c\uac1c"}],"readingTime":4.72,"hasTruncateMarker":true,"authors":[{"name":"LeeSeungBeen","url":"https://github.com/Pyorang","email":"sudangi143@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/144720218?v=4","key":"Pyorang"}],"frontMatter":{"date":"2025-05-05T00:00:00.000Z","authors":"Pyorang","title":"BCSD \uac00\uc774\ub4dc: \uac8c\uc784","description":"\uac8c\uc784 \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!","keywords":["Game","\ud2b8\ub799 \uc18c\uac1c"],"tags":["Game","\ud2b8\ub799 \uc18c\uac1c"]},"unlisted":false},"content":"\uac8c\uc784 \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!\\n\\n{/* truncate */}\\n\\n# **BCSD Game Track Introduce**\\n\\n\uc548\ub155\ud558\uc138\uc694! BCSD Game Track\uc5d0 \uc624\uc2e0 \uac83\uc744 \uc9c4\uc2ec\uc73c\ub85c \ud658\uc601\ud569\ub2c8\ub2e4!\\n\\n\uc800\ud76c \uac8c\uc784 \ud2b8\ub799\uc5d0 \ub300\ud574 \uad81\uae08\ud558\uc2e4 \ub9cc\ud55c \uc810\ub4e4\uc744 \uc544\ub798\uc5d0 \uc815\ub9ac\ud574\ub450\uc5c8\uc73c\ub2c8, \ud55c \ubc88\uc529 \uc77d\uc5b4\ubcf4\uc2dc\uba74 \ub9ce\uc740 \ub3c4\uc6c0\uc774 \ub420 \uac70\uc608\uc694.\\n\\n---\\n\\n## **Q. \ub4e4\uc5b4\uc624\uba74 \uc5b4\ub5a4 \uacf5\ubd80\ub97c \ud558\uac8c \ub418\ub098\uc694?**\\n\\n\uac8c\uc784\uc744 \ub9cc\ub4dc\ub294 \ubc29\ubc95\uc5d0\ub294 \uc5ec\ub7ec \uac00\uc9c0\uac00 \uc788\uc9c0\ub9cc,\\n\\n\ube44\uae30\ub108 \ud2b8\ub799\uc5d0\uc11c\ub294 **\uac00\uc7a5 \ub300\ud45c\uc801\uc778 \uac8c\uc784 \uc5d4\uc9c4\uc778 Unity**\ub97c \uc911\uc2ec\uc73c\ub85c \ubc30\uc6b0\uac8c \ub429\ub2c8\ub2e4.\\n\\nUnity\ub97c \uc0ac\uc6a9\ud558\uae30 \uc704\ud574 **\uae30\ucd08 \uc5b8\uc5b4\uc778 C#**\ubd80\ud130 \uc2dc\uc791\ud574, **2D\uc640 3D \uac8c\uc784 \uac1c\ubc1c**\uc744 \ub2e8\uacc4\uc801\uc73c\ub85c \uc775\ud799\ub2c8\ub2e4.\\n\\n\uc790\uc138\ud55c \ucee4\ub9ac\ud058\ub7fc\uc740 [BCSD \ud648\ud398\uc774\uc9c0](https://bcsdlab.com/track/game)\uc5d0\uc11c \ud655\uc778\ud558\uc2e4 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. C#\uc740 \uc5b4\ub5a4 \uc5b8\uc5b4\uc778\uac00\uc694?**\\n\\n\uac04\ub2e8\ud558\uac8c \ube44\uc720\ud558\uc790\uba74,\\n\\n- **C#\uc740 \uc720\ub2c8\ud2f0\uc5d0\uc11c \uac8c\uc784\uc744 \uc6c0\uc9c1\uc774\uac8c \ub9cc\ub4dc\ub294 \uc5b8\uc5b4\uc785\ub2c8\ub2e4.**\\n- \uc720\ub2c8\ud2f0\uac00 \ubb34\ub300, \uce90\ub9ad\ud130, \ubc30\uacbd \uac19\uc740 \u2018\ubaa8\uc591\u2019\uc744 \ub9cc\ub4e4\uc5b4\uc8fc\ub294 \ub3c4\uad6c\ub77c\uba74, C#\uc740 \uadf8 \uc548\uc5d0\uc11c \u2018\uc5b4\ub5bb\uac8c \uc6c0\uc9c1\uc77c\uc9c0, \uc5b4\ub5a4 \uc77c\uc774 \uc77c\uc5b4\ub0a0\uc9c0\u2019\ub97c \uc815\ud558\ub294 \uc5b8\uc5b4\ub77c\uace0 \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\nC#\uc740 \ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8\uc5d0\uc11c \uac1c\ubc1c\ud55c **\uac1d\uccb4 \uc9c0\ud5a5 \ud504\ub85c\uadf8\ub798\ubc0d \uc5b8\uc5b4**\ub85c, Java\uc640 C++\uc758 \uc601\ud5a5\uc744 \ubc1b\uc544 \ub9cc\ub4e4\uc5b4\uc84c\uc2b5\ub2c8\ub2e4.\\n\\n.NET \ud504\ub808\uc784\uc6cc\ud06c\ub97c \uae30\ubc18\uc73c\ub85c \ud558\uba70, \uc624\ud508\uc18c\uc2a4\ud654\ub85c \uc778\ud574 Windows\ubfd0\ub9cc \uc544\ub2c8\ub77c \ub2e4\uc591\ud55c \ubd84\uc57c\uc5d0\uc11c \uc0ac\uc6a9\ub418\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n.NET\uc774\ub780, C#\uc744 \ud3ec\ud568\ud55c \uc5ec\ub7ec \uc5b8\uc5b4\ub97c \uc9c0\uc6d0\ud558\ub294 **\ud504\ub808\uc784\uc6cc\ud06c\uc774\uc790 \uc2e4\ud589 \ud658\uacbd**\uc785\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ub808\uade4\ub7ec\uac00 \ub418\uba74 \uc5b4\ub5a4 \ud65c\ub3d9\uc744 \ud558\ub098\uc694?**\\n\\n\ube44\uae30\ub108 \ucee4\ub9ac\ud058\ub7fc\uc5d0\uc11c \ubc30\uc6b4 \ub0b4\uc6a9\uc744 \ubc14\ud0d5\uc73c\ub85c **\uc9c1\uc811 \uac8c\uc784\uc744 \uc81c\uc791**\ud574\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\uc758\uacac\uc774 \ub9de\ub294 \ubd80\uc6d0\ub4e4\uacfc **\ud300\uc744 \uc774\ub8e8\uc5b4 \uae30\ud68d\ubd80\ud130 \ubc30\ud3ec\uae4c\uc9c0 \ud504\ub85c\uc81d\ud2b8**\ub97c \uc9c4\ud589\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ub610\ud55c,\\n\\n- Unity \uc5d4\uc9c4\ubfd0\ub9cc \uc544\ub2c8\ub77c **Unreal Engine**\uc744 \uc0c8\ub86d\uac8c \ubc30\uc6cc\ubcfc \uc218\ub3c4 \uc788\uace0,\\n- \uac8c\uc784 \uac1c\ubc1c \uc804 \uc791\uc131\ud558\ub294 **\uae30\ud68d\uc11c \uc791\uc131\ubc95**\ub3c4 \ub354\uc6b1 \uad6c\uccb4\uc801\uc774\uace0 \uccb4\uacc4\uc801\uc73c\ub85c \uc2ec\ud654 \ud559\uc2b5\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- **\uac8c\uc784\uc7bc, \uac8c\uc784 \uac1c\ubc1c \ucee8\ud37c\ub7f0\uc2a4** \ub4f1 \ub2e4\uc591\ud55c \ud589\uc0ac\uc5d0 \ucc38\uc5ec\ud558\uba74\uc11c \uac8c\uc784 \uac1c\ubc1c\uc5d0 \ub300\ud55c \ud3ed\ub113\uc740 \uc9c0\uc2dd\uacfc \uacbd\ud5d8\uc744 \uc313\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## **Q. \ub09c\uc774\ub3c4\ub294 \uc5b4\ub290 \uc815\ub3c4\uc778\uac00\uc694?**\\n\\n- **C#\uc740 \uc790\ubc14\uc640 \ub9e4\uc6b0 \uc720\uc0ac\ud55c \uc5b8\uc5b4**\uc785\ub2c8\ub2e4. 2\ud559\ub144 \ub54c \uc790\ubc14 \uc218\uc5c5\uc744 \uc798 \ub4e4\uc73c\uc168\ub2e4\uba74, \ube44\uae30\ub108 \uacfc\uc81c \uc218\ud589 \uc2dc\uac04\uc774 \ud06c\uac8c \ub2e8\ucd95\ub420 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- \uac8c\uc784 \uac1c\ubc1c\uc5d0\ub294 **\uc218\ud559\uc801\uc778 \uc0ac\uace0\ub825**\ub3c4 \uc694\uad6c\ub418\uae30 \ub54c\ubb38\uc5d0, \uc218\ud559 \uad00\ub828 \uacfc\ubaa9\uc744 \uc798 \uc218\uac15\ud558\uc168\ub2e4\uba74 \ub354 \uc218\uc6d4\ud558\uac8c \uc9c4\ud589\ud558\uc2e4 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- \uc0c8\ub85c\uc6b4 \uac83\uc744 \ubc30\uc6b8 \ub54c\ub294 **\uc9c1\uc811 \ub530\ub77c \ud574\ubcf4\ub294 \uac83\uc774 \uac00\uc7a5 \ud6a8\uacfc\uc801**\uc785\ub2c8\ub2e4. \uadf8\ub798\uc11c Unity 2D\ub97c \ubc30\uc6b0\ub294 \uacfc\uc815\uc5d0\uc11c\ub294 **\uc2e4\uc2b5 \uc704\uc8fc\uc758 \uacfc\uc81c**\uac00 \ub9ce\uc774 \uc8fc\uc5b4\uc9c8 \uc608\uc815\uc785\ub2c8\ub2e4.\\n\\n\ube44\uae30\ub108\ub85c \ub4e4\uc5b4\uc624\uc2dc\uae30 \uc804\uc5d0\ub294 \ud559\uad50 \uc218\uc5c5\uacfc \uac1c\uc778 \uc77c\uc815 \ub4f1\uc744 \uace0\ub824\ud574 \ubcf4\uc2dc\uace0,\\n\\n**\ubcf8\uc778\uc774 \uac8c\uc784 \uac1c\ubc1c\uc5d0 \uc9c4\uc2ec\uc778\uc9c0 \ud55c \ubc88\ucbe4 \uace0\ubbfc\ud574\ubcf4\uc2e0 \ub4a4\uc5d0 \uacb0\uc815**\ud558\uc2dc\ub294 \uac78 \ucd94\ucc9c\ub4dc\ub9bd\ub2c8\ub2e4.\\n\\n---\\n\\n**\ub9c8\ubb34\ub9ac**\\n\\n\uc5ec\uae30\uc11c \ubc30\uc6b0\ub294 \uacfc\uc815\uc740 \uc27d\uc9c0 \uc54a\uc744 \uc218 \uc788\uc9c0\ub9cc, \ub05d\uae4c\uc9c0 \ub3c4\uc804\ud55c\ub2e4\uba74 \uac1c\ubc1c\uc790 \uc2dc\uc7a5\uc5d0\uc11c \ub2f9\ub2f9\ud788 1\uc778\ubd84\uc744 \ud560 \uc218 \uc788\ub294 \uc2e4\ub825\uc744 \uac16\ucd94\uac8c \ub420 \uac83\uc785\ub2c8\ub2e4.\\n\\n\uc5ec\ub7ec\ubd84\uc774 \uc2e4\uc81c\ub85c \uac8c\uc784\uc744 \ub9cc\ub4e4\uace0, \ud300 \ud504\ub85c\uc81d\ud2b8\ub97c \uc644\uc8fc\ud558\ub294 \uadf8 \uc21c\uac04\uae4c\uc9c0 BCSD\uac00 \ud568\uaed8 \ud558\uaca0\uc2b5\ub2c8\ub2e4."}]}')}}]);